import{_ as e}from"./chunks/quickstart_01.CAs9iatn.js";import{_ as a,o as r,c as s,a2 as i}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"クイックスタート","description":"","frontmatter":{},"headers":[],"relativePath":"ja/getting-started/quickstart.md","filePath":"ja/getting-started/quickstart.md"}'),o={name:"ja/getting-started/quickstart.md"};function l(c,t,n,d,p,g){return r(),s("div",null,[...t[0]||(t[0]=[i('<h1 id="クイックスタート" tabindex="-1"><i class="ph ph-target"></i> クイックスタート <a class="header-anchor" href="#クイックスタート" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-target&quot;&gt;&lt;/i&gt; クイックスタート&quot;">​</a></h1><p>WebAPプラグインは、<em>プラグアンドプレイ</em>のアプローチで設計されています。コードを書いたり、開始シーンにマネージャーを追加したりする必要はありません — システムは自動的に初期化されます。</p><h2 id="_1-プラグインを有効にする" tabindex="-1">1. プラグインを有効にする <a class="header-anchor" href="#_1-プラグインを有効にする" aria-label="Permalink to &quot;1. プラグインを有効にする&quot;">​</a></h2><ol><li><strong>Edit -&gt; Project Settings -&gt; Adaptive Performance (Web)</strong> に移動します。</li><li><strong>Enable Web Adaptive Performance</strong> チェックボックスをオンにします。</li><li>Scalersタブを展開し、ゲームの特性に最も適した追加モジュール（物理ステップやシャドウ品質など）を有効にします（詳細は<a href="./../scalers/reference">スケーラーリファレンス</a>を参照）。</li></ol><p><img src="'+e+'" alt=""></p><div class="info custom-block"><p class="custom-block-title">デフォルト設定</p><p>デフォルト設定は、ほとんどのプロジェクトで最適なパフォーマンスを提供するようにあらかじめ構成されています。そのままにしておいてください。</p></div><h2 id="_2-player-settings-の構成" tabindex="-1">2. Player Settings の構成 <a class="header-anchor" href="#_2-player-settings-の構成" aria-label="Permalink to &quot;2. Player Settings の構成&quot;">​</a></h2><p>プラグインのトラッカー（Tracker）がプロセッサ（CPU）のラグとビデオカード（GPU）のラグを数学的に区別するためには、ハードウェアの正確なフレームタイミングにアクセスする必要があります。</p><div class="warning custom-block"><p class="custom-block-title">フレームタイミングの統計 (Frame Timing Stats)</p><p><strong>Edit -&gt; Project Settings -&gt; Player -&gt; Other Settings -&gt; Rendering</strong> に移動し、<strong>Frame Timing Stats</strong> にチェックを入れてください。この設定がないと、ボトルネックの検出が機能しません。</p></div><h2 id="_3-グラフィックの設定" tabindex="-1">3. グラフィックの設定 <a class="header-anchor" href="#_3-グラフィックの設定" aria-label="Permalink to &quot;3. グラフィックの設定&quot;">​</a></h2><p>異なるデバイス向けに別々の品質プリセット（Low、Medium、High）を作成し、プレイヤーに手動で選択させるのはやめましょう。</p><div class="tip custom-block"><p class="custom-block-title">グラフィック品質を最大化する</p><p>プロジェクトを最大品質で構成します。BiRPの場合は <code>Project Settings -&gt; Quality</code> で、URPの場合は <code>URP Asset</code> 内で設定します。プレイヤーのデバイスにパフォーマンスの余裕（Performance Headroom）が足りない場合、プラグインは実行時に、有効にしたスケーラーのみを使用して、スムーズかつ自動的に負荷を軽減します。</p></div>',12)])])}const u=a(o,[["render",l]]);export{h as __pageData,u as default};
